changeSet.sql:
COMMENT ON TABLE patient_measure_overrides IS 'Patient-specific measure parameter overrides with clinical justification and approval workflow';
COMMENT ON COLUMN patient_measure_overrides.override_type IS 'THRESHOLD, PARAMETER, EXCLUSION, INCLUSION_CRITERIA, TARGET_VALUE';
COMMENT ON COLUMN patient_measure_overrides.value_type IS 'NUMERIC, DATE, BOOLEAN, TEXT, JSON - defines how to parse override_value';
COMMENT ON COLUMN patient_measure_overrides.clinical_reason IS 'REQUIRED: Clinical justification for this override (HIPAA compliance)';
COMMENT ON COLUMN patient_measure_overrides.supporting_evidence IS 'Links to clinical notes, lab results, encounters supporting this override';
COMMENT ON COLUMN patient_measure_overrides.requires_periodic_review IS 'If true, override must be reviewed at review_frequency_days interval';

ALTER TABLE patient_measure_overrides
    ADD CONSTRAINT chk_pmo_override_type
        CHECK (override_type IN ('THRESHOLD', 'PARAMETER', 'EXCLUSION', 'INCLUSION_CRITERIA', 'TARGET_VALUE', 'FREQUENCY'));

ALTER TABLE patient_measure_overrides
    ADD CONSTRAINT chk_pmo_value_type
        CHECK (value_type IN ('NUMERIC', 'DATE', 'BOOLEAN', 'TEXT', 'JSON'));

ALTER TABLE patient_measure_overrides
    ADD CONSTRAINT chk_pmo_effective_dates
        CHECK (effective_until IS NULL OR effective_until >= effective_from);

ALTER TABLE patient_measure_overrides
    ADD CONSTRAINT chk_pmo_approval
        CHECK (
            (approved_by IS NULL AND approved_at IS NULL) OR
            (approved_by IS NOT NULL AND approved_at IS NOT NULL)
        );

ALTER TABLE patient_measure_overrides
    ADD CONSTRAINT chk_pmo_review
        CHECK (
            (requires_periodic_review = false) OR
            (requires_periodic_review = true AND review_frequency_days > 0)
        );

rollback.sql:
ALTER TABLE patient_measure_overrides DROP CONSTRAINT IF EXISTS chk_pmo_override_type;
ALTER TABLE patient_measure_overrides DROP CONSTRAINT IF EXISTS chk_pmo_value_type;
ALTER TABLE patient_measure_overrides DROP CONSTRAINT IF EXISTS chk_pmo_effective_dates;
ALTER TABLE patient_measure_overrides DROP CONSTRAINT IF EXISTS chk_pmo_approval;
ALTER TABLE patient_measure_overrides DROP CONSTRAINT IF EXISTS chk_pmo_review;

changeSet.sql:
CREATE OR REPLACE FUNCTION calculate_next_review_date()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.requires_periodic_review = true AND NEW.active = true THEN
        IF NEW.last_reviewed_at IS NULL THEN
            -- First review based on creation date
            NEW.next_review_date := (NEW.created_at + (NEW.review_frequency_days || ' days')::INTERVAL)::DATE;
        ELSE
            -- Subsequent reviews based on last review
            NEW.next_review_date := (NEW.last_reviewed_at + (NEW.review_frequency_days || ' days')::INTERVAL)::DATE;
        END IF;
    ELSE
        NEW.next_review_date := NULL;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_pmo_calculate_next_review
    BEFORE INSERT OR UPDATE ON patient_measure_overrides
    FOR EACH ROW
    EXECUTE FUNCTION calculate_next_review_date();
